mapper.select:
SELECT id, task_id, task_name, task_group, trigger_type, execute_status, execute_start_time, execute_end_time, execute_duration, execute_result, error_message, retry_count, created_time FROM task_log WHERE 1=1
AND task_id = #{query.taskId}
AND task_name LIKE CONCAT('%', #{query.taskName}, '%')
AND task_group = #{query.taskGroup}
AND execute_status = #{query.executeStatus}
AND trigger_type = #{query.triggerType}
AND execute_start_time >= #{query.startTime}
AND execute_start_time <= #{query.endTime}
ORDER BY execute_start_time DESC, id DESC
